    val n = prices.size
    val originalContribution = LongArray(n)
    originalContribution[0] = strategy[0] * prices[0]
    for (i in 1 until n) {
        originalContribution[i] = originalContribution[i - 1] + strategy[i] * prices[i]
    }

    val prefixPrices = LongArray(n)
    prefixPrices[0] = prices[0]
    for (i in 1 until n) {
        prefixPrices[i] = prefixPrices[i - 1] + prices[i]
    }

    val originalProfit = originalContribution[n - 1]
    var maxGain = 0L

    val halfK = k / 2
    for (i in 0 until (n - k + 1)) {
        val end = i + k - 1
        val originalWindow = originalContribution[end] - (if (i > 0) originalContribution[i - 1] else 0L)

        val startSecondHalf = i + halfK
        val endSecondHalf = end

        var sumSecondHalf = 0L
        if (startSecondHalf == 0) {
            sumSecondHalf = prefixPrices[endSecondHalf]
        } else {
            sumSecondHalf = prefixPrices[endSecondHalf] - prefixPrices[startSecondHalf - 1]
        }

        val gain = sumSecondHalf - originalWindow
        if (gain > maxGain) {
            maxGain = gain
        }
    }

    return originalProfit + max(0L, maxGain)
