    val n = prices.size
    val originalProfit = prices.zip(strategy).sumOf { (p, s) -> s * p }

    val m = k / 2
    val preA = LongArray(n + 1)
    val preB = LongArray(n + 1)

    for (i in 0 until n) {
        preA[i + 1] = preA[i] + (-strategy[i] * prices[i])
        preB[i + 1] = preB[i] + (1 - strategy[i]) * prices[i]
    }

    var maxGain = 0L
    val maxStart = n - k
    for (start in 0..maxStart) {
        val sumA = preA[start + m] - preA[start]
        val sumB = preB[start + k] - preB[start + m]
        val gain = sumA + sumB
        if (gain > maxGain) {
            maxGain = gain
        }
    }

    return originalProfit + max(0L, maxGain)
}
